// Regenerates registry/css/all.css — a convenience bundle that pulls in the
// design tokens (index.css) plus every component stylesheet via @import, so a
// vanilla-HTML user can link a single file and get the whole system.
//
// Run after adding or removing a component stylesheet:
//   node registry/scripts/build-css-bundle.mjs
import { readdirSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const cssDir = join(__dirname, "..", "css");

// Files that are not component stylesheets and must not be imported as components.
// breakpoints.css holds responsive tokens — imported right after index.css below.
const EXCLUDE = new Set(["index.css", "breakpoints.css", "all.css"]);

const components = readdirSync(cssDir)
  .filter((f) => f.endsWith(".css") && !EXCLUDE.has(f))
  .sort();

const lines = [
  "/* JLDS — full bundle. Auto-generated by scripts/build-css-bundle.mjs — do not edit by hand. */",
  "/* Design tokens + base resets, then every component stylesheet. Link this one file to get everything. */",
  "",
  '@import "./index.css";', // index.css @imports breakpoints.css, so the bundle gets the responsive tokens transitively
  "",
  ...components.map((f) => `@import "./${f}";`),
  "",
];

writeFileSync(join(cssDir, "all.css"), lines.join("\n"));
console.log(`Wrote registry/css/all.css (${components.length} components)`);
